#!/usr/bin/env python3
"""Verify a rank-K sketch KNOT header without dequantizing the payload.

This is the admission gate for large sketch bundles such as
qwen-72b-gkq-sketches.knot. It checks the KNOT envelope, metadata shape,
sketch coverage, contiguous payload offsets, and selected tensor dimensions
while keeping memory bounded by the metadata JSON.
"""

from __future__ import annotations

import argparse
import json
import os
import struct
import sys
from pathlib import Path
from typing import Dict, Iterable, Optional, Tuple


def parse_args(argv=None):
    p = argparse.ArgumentParser(description="Verify a <model>-sketches.knot header")
    p.add_argument("path", help="Local sketch KNOT path")
    p.add_argument("--expect-rank", type=int, default=None)
    p.add_argument("--expect-sketches", type=int, default=None)
    p.add_argument("--min-sketches", type=int, default=None)
    p.add_argument("--expect-arch", default=None)
    p.add_argument("--expect-layers", type=int, default=None)
    p.add_argument("--expect-hidden", type=int, default=None)
    p.add_argument("--expect-vocab", type=int, default=None)
    p.add_argument(
        "--require-sketch",
        action="append",
        default=[],
        help="Sketch name that must be present; repeatable",
    )
    p.add_argument(
        "--expect-sketch-shape",
        action="append",
        default=[],
        metavar="NAME:D_OUT:D_IN",
        help="Expected sketch dimensions; repeatable",
    )
    p.add_argument("--json", action="store_true", help="Print summary JSON")
    return p.parse_args(argv)


def read_header(path: Path) -> Tuple[dict, int, int]:
    with open(path, "rb") as f:
        magic = f.read(4)
        if magic != b"KNOT":
            raise ValueError(f"bad magic {magic!r}; expected b'KNOT'")
        version_raw = f.read(2)
        if len(version_raw) != 2:
            raise ValueError("missing KNOT version")
        (version,) = struct.unpack("<H", version_raw)
        if version != 1:
            raise ValueError(f"unsupported KNOT version {version}")
        meta_len_raw = f.read(4)
        if len(meta_len_raw) != 4:
            raise ValueError("missing KNOT metadata length")
        (meta_len,) = struct.unpack("<I", meta_len_raw)
        meta_raw = f.read(meta_len)
        if len(meta_raw) != meta_len:
            raise ValueError(f"metadata truncated: {len(meta_raw)} < {meta_len}")
        metadata = json.loads(meta_raw.decode("utf-8"))
        cur = 10 + meta_len
        pad_len = ((cur + 3) & ~3) - cur
        if pad_len:
            f.read(pad_len)
        marker = f.read(1)
        if marker != b"\x20":
            raise ValueError(f"unexpected codec marker {marker!r}; expected 0x20")
        payload_offset = f.tell()
    return metadata, meta_len, payload_offset


def require_int(value: object, label: str) -> int:
    if not isinstance(value, int):
        raise ValueError(f"{label} must be an integer, got {value!r}")
    return value


def config_int(config: dict, *keys: str) -> Optional[int]:
    for key in keys:
        value = config.get(key)
        if isinstance(value, int):
            return value
        if isinstance(value, float) and value.is_integer():
            return int(value)
    return None


def config_str(config: dict, *keys: str) -> Optional[str]:
    for key in keys:
        value = config.get(key)
        if isinstance(value, str):
            return value
    return None


def parse_shape_specs(specs: Iterable[str]) -> Dict[str, Tuple[int, int]]:
    parsed: Dict[str, Tuple[int, int]] = {}
    for spec in specs:
        pieces = spec.rsplit(":", 2)
        if len(pieces) != 3:
            raise ValueError(f"bad --expect-sketch-shape {spec!r}; use NAME:D_OUT:D_IN")
        name, d_out, d_in = pieces
        parsed[name] = (int(d_out), int(d_in))
    return parsed


def verify(args) -> dict:
    path = Path(args.path)
    metadata, meta_len, payload_offset = read_header(path)
    file_size = path.stat().st_size
    payload_bytes = file_size - payload_offset
    if payload_bytes < 0:
        raise ValueError("payload offset exceeds file size")

    if metadata.get("topology") != "rank-k-exclusion-sketch":
        raise ValueError(f"unexpected topology {metadata.get('topology')!r}")
    if metadata.get("format_version") != 1:
        raise ValueError(f"unexpected sketch format_version {metadata.get('format_version')!r}")
    if metadata.get("codec") != "fp32":
        raise ValueError(f"unexpected codec {metadata.get('codec')!r}")

    sketches = metadata.get("sketches")
    if not isinstance(sketches, dict):
        raise ValueError("metadata.sketches must be an object")
    config = metadata.get("config")
    if not isinstance(config, dict):
        raise ValueError("metadata.config must be an object")

    rank_default = require_int(metadata.get("sketch_rank_default"), "sketch_rank_default")
    if args.expect_rank is not None and rank_default != args.expect_rank:
        raise ValueError(f"rank mismatch: expected {args.expect_rank}, observed {rank_default}")
    if args.expect_sketches is not None and len(sketches) != args.expect_sketches:
        raise ValueError(
            f"sketch count mismatch: expected {args.expect_sketches}, observed {len(sketches)}"
        )
    if args.min_sketches is not None and len(sketches) < args.min_sketches:
        raise ValueError(f"too few sketches: expected >= {args.min_sketches}, observed {len(sketches)}")

    observed_arch = config_str(config, "arch", "architecture")
    observed_layers = config_int(config, "num_layers", "numLayers", "layers")
    observed_hidden = config_int(config, "hidden_dim", "hiddenDim", "hidden_size")
    observed_vocab = config_int(config, "vocab_size", "vocabSize")
    expected_config = [
        ("arch", args.expect_arch, observed_arch),
        ("layers", args.expect_layers, observed_layers),
        ("hidden", args.expect_hidden, observed_hidden),
        ("vocab", args.expect_vocab, observed_vocab),
    ]
    for label, expected, observed in expected_config:
        if expected is not None and observed != expected:
            raise ValueError(f"{label} mismatch: expected {expected}, observed {observed}")

    for name in args.require_sketch:
        if name not in sketches:
            raise ValueError(f"missing required sketch {name!r}")

    for name, (d_out_expected, d_in_expected) in parse_shape_specs(args.expect_sketch_shape).items():
        info = sketches.get(name)
        if not isinstance(info, dict):
            raise ValueError(f"missing sketch shape entry {name!r}")
        observed = (require_int(info.get("d_out"), f"{name}.d_out"), require_int(info.get("d_in"), f"{name}.d_in"))
        if observed != (d_out_expected, d_in_expected):
            raise ValueError(
                f"{name} shape mismatch: expected {(d_out_expected, d_in_expected)}, observed {observed}"
            )

    expected_offset = 0
    for name, info_obj in sorted(sketches.items(), key=lambda item: int(item[1]["offset"])):
        if not isinstance(info_obj, dict):
            raise ValueError(f"{name}: sketch info must be an object")
        offset = require_int(info_obj.get("offset"), f"{name}.offset")
        length = require_int(info_obj.get("length"), f"{name}.length")
        d_out = require_int(info_obj.get("d_out"), f"{name}.d_out")
        d_in = require_int(info_obj.get("d_in"), f"{name}.d_in")
        rank = require_int(info_obj.get("rank"), f"{name}.rank")
        u_len = require_int(info_obj.get("u_q8_len"), f"{name}.u_q8_len")
        sigma_len = require_int(info_obj.get("sigma_q8_len"), f"{name}.sigma_q8_len")
        v_len = require_int(info_obj.get("v_q8_len"), f"{name}.v_q8_len")
        if info_obj.get("type") != "SK32":
            raise ValueError(f"{name}: unexpected sketch type {info_obj.get('type')!r}")
        if offset != expected_offset:
            raise ValueError(f"{name}: offset gap/overlap, expected {expected_offset}, observed {offset}")
        if u_len != d_out * rank:
            raise ValueError(f"{name}: u_q8_len mismatch")
        if sigma_len != rank:
            raise ValueError(f"{name}: sigma_q8_len mismatch")
        if v_len != rank * d_in:
            raise ValueError(f"{name}: v_q8_len mismatch")
        if length != u_len + sigma_len + v_len:
            raise ValueError(f"{name}: length mismatch")
        expected_offset += length

    if expected_offset != payload_bytes:
        raise ValueError(f"payload size mismatch: metadata {expected_offset}, file {payload_bytes}")

    return {
        "path": str(path),
        "file_size_bytes": file_size,
        "metadata_bytes": meta_len,
        "payload_offset": payload_offset,
        "payload_bytes": payload_bytes,
        "rank": rank_default,
        "sketches": len(sketches),
        "config": {
            "arch": observed_arch,
            "layers": observed_layers,
            "hidden": observed_hidden,
            "vocab": observed_vocab,
        },
    }


def main(argv=None) -> int:
    args = parse_args(argv)
    try:
        summary = verify(args)
    except Exception as exc:
        print(f"[verify-sketch-knot] FAIL: {exc}", file=sys.stderr)
        return 1
    if args.json:
        print(json.dumps(summary, indent=2, sort_keys=True))
    else:
        print(
            "[verify-sketch-knot] OK "
            f"sketches={summary['sketches']} rank={summary['rank']} "
            f"payload={summary['payload_bytes']:,} bytes "
            f"config={summary['config']}"
        )
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
